class SearchProblem:
    name: str
    instance_id: str

    def initial_state(self) -> State:
        raise NotImplementedError

    def actions(self, state: State) -> List[Action]:
        raise NotImplementedError

    def step(self, state: State, action: Action) -> State:
        raise NotImplementedError

    def is_terminal(self, state: State) -> bool:
        raise NotImplementedError

    def evaluate_state(self, state: State) -> float:
        raise NotImplementedError

    def optimal_score(self) -> Optional[float]:
        return None

    def greedy_action(self, state: State) -> Optional[Action]:
        actions = self.actions(state)
        if not actions:
            return None
        return max(
            actions, key=lambda action: self.evaluate_state(self.step(state, action))
        )


@dataclass
class GridRewardProblem(SearchProblem):
    rewards: Dict[Tuple[int, int], float]
    blocked: frozenset[Tuple[int, int]]
    start: Tuple[int, int]
    size: int
    max_steps: int
    instance_id: str
    name: str = "grid_reward_collection"

    def __post_init__(self) -> None:
        self.reward_positions = sorted(self.rewards)
        self.reward_to_bit = {pos: i for i, pos in enumerate(self.reward_positions)}
        self.full_mask = (1 << len(self.reward_positions)) - 1

    def initial_state(self) -> State:
        return (self.start[0], self.start[1], self.full_mask, 0, 0.0)

    def actions(self, state: State) -> List[Action]:
        row, col, _, steps, _ = state
        if steps >= self.max_steps:
            return []
        moves = []
        for name, dr, dc in [("U", -1, 0), ("D", 1, 0), ("L", 0, -1), ("R", 0, 1)]:
            nr, nc = row + dr, col + dc
            if (
                0 <= nr < self.size
                and 0 <= nc < self.size
                and (nr, nc) not in self.blocked
            ):
                moves.append(name)
        return moves

    def step(self, state: State, action: Action) -> State:
        row, col, mask, steps, score = state
        delta = {"U": (-1, 0), "D": (1, 0), "L": (0, -1), "R": (0, 1)}[action]
        nr, nc = row + delta[0], col + delta[1]
        if (
            not (0 <= nr < self.size and 0 <= nc < self.size)
            or (nr, nc) in self.blocked
        ):
            nr, nc = row, col
        new_mask = mask
        new_score = score - 0.03
        bit = self.reward_to_bit.get((nr, nc))
        if bit is not None and (mask & (1 << bit)):
            new_mask &= ~(1 << bit)
            new_score += float(self.rewards[(nr, nc)])
        return (nr, nc, new_mask, steps + 1, new_score)

    def is_terminal(self, state: State) -> bool:
        _, _, mask, steps, _ = state
        return steps >= self.max_steps or mask == 0

    def evaluate_state(self, state: State) -> float:
        return float(state[4])

    def optimal_score(self) -> Optional[float]:
        @lru_cache(maxsize=None)
        def best(row: int, col: int, mask: int, steps: int) -> float:
            if steps >= self.max_steps or mask == 0:
                return 0.0
            state = (row, col, mask, steps, 0.0)
            actions = self.actions(state)
            if not actions:
                return 0.0
            best_value = -float("inf")
            for action in actions:
                nr, nc, new_mask, _, delta_score = self.step(state, action)
                value = float(delta_score) + best(
                    int(nr), int(nc), int(new_mask), steps + 1
                )
                best_value = max(best_value, value)
            return best_value

        s = self.initial_state()
        return best(int(s[0]), int(s[1]), int(s[2]), int(s[3]))

    def greedy_action(self, state: State) -> Optional[Action]:
        actions = self.actions(state)
        if not actions:
            return None
        _, _, mask, _, _ = state

        def score(action: Action) -> float:
            next_state = self.step(state, action)
            nr, nc = next_state[0], next_state[1]
            immediate = self.evaluate_state(next_state) - self.evaluate_state(state)
            future = 0.0
            for pos, reward in self.rewards.items():
                bit = self.reward_to_bit[pos]
                if mask & (1 << bit):
                    dist = abs(nr - pos[0]) + abs(nc - pos[1])
                    future = max(future, reward / (1.0 + dist))
            return immediate + 0.15 * future

        return max(actions, key=score)


@dataclass
class GraphOrienteeringProblem(SearchProblem):
    travel_time: np.ndarray
    rewards: np.ndarray
    start: int
    max_time: int
    instance_id: str
    name: str = "graph_orienteering"

    def __post_init__(self) -> None:
        self.n_nodes = int(len(self.rewards))
        self.full_mask = (1 << self.n_nodes) - 1
        self.start_mask = self.full_mask & ~(1 << self.start)

    def initial_state(self) -> State:
        return (self.start, self.start_mask, 0, 0.0)

    def actions(self, state: State) -> List[Action]:
        node, mask, time_used, _ = state
        actions = []
        for nxt in range(self.n_nodes):
            if mask & (1 << nxt):
                travel = int(self.travel_time[node, nxt])
                if time_used + travel <= self.max_time:
                    actions.append(nxt)
        return actions

    def step(self, state: State, action: Action) -> State:
        node, mask, time_used, score = state
        travel = int(self.travel_time[node, action])
        new_time = time_used + travel
        new_mask = mask & ~(1 << int(action))
        new_score = score + float(self.rewards[action]) - 0.02 * travel
        return (int(action), new_mask, new_time, new_score)

    def is_terminal(self, state: State) -> bool:
        return len(self.actions(state)) == 0

    def evaluate_state(self, state: State) -> float:
        return float(state[3])

    def optimal_score(self) -> Optional[float]:
        @lru_cache(maxsize=None)
        def best(node: int, mask: int, time_used: int) -> float:
            state = (node, mask, time_used, 0.0)
            actions = self.actions(state)
            if not actions:
                return 0.0
            best_value = -float("inf")
            for action in actions:
                ns = self.step(state, action)
                value = float(ns[3]) + best(int(ns[0]), int(ns[1]), int(ns[2]))
                best_value = max(best_value, value)
            return best_value

        s = self.initial_state()
        return best(int(s[0]), int(s[1]), int(s[2]))

    def greedy_action(self, state: State) -> Optional[Action]:
        actions = self.actions(state)
        if not actions:
            return None
        node, _, _, _ = state
        return max(
            actions,
            key=lambda nxt: self.rewards[nxt] / max(self.travel_time[node, nxt], 1.0),
        )


@dataclass
class TaskSchedulingProblem(SearchProblem):
    durations: np.ndarray
    deadlines: np.ndarray
    priorities: np.ndarray
    machine_count: int
    instance_id: str
    precedence: Optional[Dict[int, Tuple[int, ...]]] = None
    name: str = "deadline_task_scheduling"

    def __post_init__(self) -> None:
        self.n_tasks = int(len(self.durations))
        self.full_mask = (1 << self.n_tasks) - 1
        self.precedence = self.precedence or {}
        self.predecessor_masks = {
            task: sum(1 << pred for pred in preds)
            for task, preds in self.precedence.items()
        }

    def initial_state(self) -> State:
        loads = tuple(0.0 for _ in range(self.machine_count))
        return (loads, self.full_mask, 0.0)

    def actions(self, state: State) -> List[Action]:
        _, mask, _ = state
        actions = []
        for task in range(self.n_tasks):
            if not (mask & (1 << task)):
                continue
            pred_mask = self.predecessor_masks.get(task, 0)
            if pred_mask & mask:
                continue
            actions.append(task)
        return actions

    def step(self, state: State, action: Action) -> State:
        loads, mask, score = state
        machine = int(np.argmin(loads))
        new_loads = list(loads)
        completion = new_loads[machine] + float(self.durations[action])
        new_loads[machine] = completion
        tardiness = max(0.0, completion - float(self.deadlines[action]))
        reward = (
            1.5 * float(self.priorities[action])
            - 0.18 * float(self.priorities[action]) * tardiness
        )
        return (tuple(new_loads), mask & ~(1 << int(action)), score + reward)

    def is_terminal(self, state: State) -> bool:
        return state[1] == 0

    def evaluate_state(self, state: State) -> float:
        return float(state[2])

    def greedy_action(self, state: State) -> Optional[Action]:
        actions = self.actions(state)
        if not actions:
            return None
        loads, _, _ = state
        earliest_machine_load = min(loads)

        def priority_density(task: int) -> float:
            slack = max(float(self.deadlines[task]) - earliest_machine_load, 1.0)
            return float(self.priorities[task]) / (float(self.durations[task]) * slack)

        return max(actions, key=priority_density)


@dataclass
class MCTSNode:
    state: State
    parent: Optional["MCTSNode"]
    action: Optional[Action]
    untried_actions: List[Action]
    children: Dict[Action, "MCTSNode"] = field(default_factory=dict)
    visits: int = 0
    value_sum: float = 0.0

    @property
    def mean_value(self) -> float:
        return self.value_sum / max(self.visits, 1)


def uct_select_child(node: MCTSNode, exploration_constant: float = 1.4) -> MCTSNode:
    log_parent = math.log(max(node.visits, 1))

    def uct_score(child: MCTSNode) -> float:
        if child.visits == 0:
            return float("inf")
        exploration = exploration_constant * math.sqrt(log_parent / child.visits)
        return child.mean_value + exploration

    return max(node.children.values(), key=uct_score)


def rollout_random(
    problem: SearchProblem, state: State, rng: np.random.Generator
) -> float:
    current = state
    while not problem.is_terminal(current):
        actions = problem.actions(current)
        if not actions:
            break
        action = actions[int(rng.integers(0, len(actions)))]
        current = problem.step(current, action)
    return problem.evaluate_state(current)


def backup_value(node: MCTSNode, value: float) -> None:
    current: Optional[MCTSNode] = node
    while current is not None:
        current.visits += 1
        current.value_sum += float(value)
        current = current.parent


def mcts_choose_action(
    problem: SearchProblem,
    root_state: State,
    per_decision_budget: int,
    rng: np.random.Generator,
    exploration_constant: float = 1.4,
) -> Optional[Action]:
    root = MCTSNode(
        state=root_state,
        parent=None,
        action=None,
        untried_actions=list(problem.actions(root_state)),
    )
    if not root.untried_actions:
        return None

    for _ in range(per_decision_budget):
        node = root
        while (
            not problem.is_terminal(node.state)
            and not node.untried_actions
            and node.children
        ):
            node = uct_select_child(node, exploration_constant=exploration_constant)

        if not problem.is_terminal(node.state) and node.untried_actions:
            idx = int(rng.integers(0, len(node.untried_actions)))
            action = node.untried_actions.pop(idx)
            next_state = problem.step(node.state, action)
            child = MCTSNode(
                state=next_state,
                parent=node,
                action=action,
                untried_actions=list(problem.actions(next_state)),
            )
            node.children[action] = child
            node = child

        value = rollout_random(problem, node.state, rng)
        backup_value(node, value)

    if not root.children:
        return root.untried_actions[0] if root.untried_actions else None
    return max(
        root.children.values(), key=lambda child: (child.visits, child.mean_value)
    ).action


def plan_with_mcts(
    problem: SearchProblem, per_decision_budget: int, rng: np.random.Generator
) -> Tuple[Plan, float]:
    state = problem.initial_state()
    plan: Plan = []
    while not problem.is_terminal(state):
        action = mcts_choose_action(
            problem, state, per_decision_budget=per_decision_budget, rng=rng
        )
        if action is None:
            break
        plan.append(action)
        state = problem.step(state, action)
    return plan, problem.evaluate_state(state)


def proposed_select_child(node: MCTSNode, context: Dict[str, Any]) -> MCTSNode:
    c = float(context.get("subtree_exploration_constant", 0.9))
    return uct_select_child(node, exploration_constant=c)


def proposed_rollout(
    problem: SearchProblem,
    state: State,
    rng: np.random.Generator,
    context: Dict[str, Any],
) -> float:
    current = state
    greedy_prob = float(context.get("rollout_greedy_prob", 0.85))
    while not problem.is_terminal(current):
        actions = problem.actions(current)
        if not actions:
            break
        use_greedy = rng.random() < greedy_prob
        action = problem.greedy_action(current) if use_greedy else None
        if action is None:
            action = actions[int(rng.integers(0, len(actions)))]
        current = problem.step(current, action)
    return problem.evaluate_state(current)


def proposed_backup(node: MCTSNode, value: float, context: Dict[str, Any]) -> None:
    _ = context
    backup_value(node, value)


def rs_allocate_round_sizes(total_budget: int, n_arms: int) -> List[int]:
    if total_budget <= 0 or n_arms <= 0:
        return []
    survivors = n_arms
    remaining = total_budget
    rounds: List[int] = []
    while survivors > 1 and remaining > 0:
        n_rounds_left = int(math.ceil(math.log2(survivors)))
        probes = max(1, remaining // max(survivors * n_rounds_left, 1))
        rounds.append(probes)
        remaining -= probes * survivors
        survivors = max(1, (survivors + 1) // 2)
    if remaining > 0:
        rounds.append(max(1, remaining))
    return rounds


def rs_shallow_probe(
    problem: SearchProblem,
    root_state: State,
    root_action: Action,
    rng: np.random.Generator,
    context: Dict[str, Any],
) -> float:
    state = problem.step(root_state, root_action)
    if problem.is_terminal(state):
        return problem.evaluate_state(state)

    depth_limit = int(context.get("subtree_depth_limit", 3))
    root = MCTSNode(
        state=state,
        parent=None,
        action=root_action,
        untried_actions=list(problem.actions(state)),
    )

    for _ in range(depth_limit):
        node = root
        depth = 0
        while (
            depth < depth_limit
            and not problem.is_terminal(node.state)
            and not node.untried_actions
            and node.children
        ):
            node = proposed_select_child(node, context)
            depth += 1

        if (
            depth < depth_limit
            and not problem.is_terminal(node.state)
            and node.untried_actions
        ):
            idx = int(rng.integers(0, len(node.untried_actions)))
            action = node.untried_actions.pop(idx)
            next_state = problem.step(node.state, action)
            child = MCTSNode(
                state=next_state,
                parent=node,
                action=action,
                untried_actions=list(problem.actions(next_state)),
            )
            node.children[action] = child
            node = child

        value = proposed_rollout(problem, node.state, rng, context)
        proposed_backup(node, value, context)

    return (
        root.mean_value
        if root.visits > 0
        else proposed_rollout(problem, state, rng, context)
    )


def proposed_mcts_choose_action(
    problem: SearchProblem,
    root_state: State,
    per_decision_budget: int,
    rng: np.random.Generator,
) -> Optional[Action]:
    root_actions = list(problem.actions(root_state))
    if not root_actions:
        return None
    if len(root_actions) == 1:
        return root_actions[0]

    context: Dict[str, Any] = {
        "problem_name": problem.name,
        "per_decision_budget": per_decision_budget,
        "subtree_exploration_constant": 0.9,
        "rollout_greedy_prob": 0.85,
        "subtree_depth_limit": (
            2 if per_decision_budget <= 16 else (3 if per_decision_budget <= 64 else 4)
        ),
    }

    active = list(root_actions)
    stats: Dict[Action, Dict[str, float]] = {
        a: {"n": 0.0, "sum": 0.0} for a in root_actions
    }
    round_sizes = rs_allocate_round_sizes(per_decision_budget, len(root_actions))

    budget_used = 0
    for probes_per_arm in round_sizes:
        if not active or budget_used >= per_decision_budget:
            break
        affordable = max(1, (per_decision_budget - budget_used) // max(len(active), 1))
        probes_this_round = min(probes_per_arm, affordable)
        if probes_this_round <= 0:
            break

        for action in active:
            for _ in range(probes_this_round):
                value = rs_shallow_probe(problem, root_state, action, rng, context)
                stats[action]["n"] += 1.0
                stats[action]["sum"] += float(value)
                budget_used += 1
                if budget_used >= per_decision_budget:
                    break
            if budget_used >= per_decision_budget:
                break

        if len(active) <= 1 or budget_used >= per_decision_budget:
            continue

        scored: List[Tuple[float, float, Action]] = []
        for action in active:
            n = stats[action]["n"]
            mean = stats[action]["sum"] / max(n, 1.0)
            radius = math.sqrt(2.0 * math.log(max(budget_used, 2)) / max(n, 1.0))
            lcb = mean - radius
            scored.append((lcb, mean, action))

        scored.sort(reverse=True)
        keep = max(1, (len(active) + 1) // 2)
        active = [a for _, _, a in scored[:keep]]

    best_action = None
    best_key = (-float("inf"), -float("inf"))
    for action in root_actions:
        n = stats[action]["n"]
        if n <= 0:
            continue
        mean = stats[action]["sum"] / n
        key = (mean, n)
        if key > best_key:
            best_key = key
            best_action = action

    if best_action is not None:
        return best_action

    return root_actions[0]


