            ax.set_title(f"Mean score: {environment}")
            ax.set_ylabel("Score")
            ax.tick_params(axis="x", rotation=45)
            fig.tight_layout()
            fig.savefig(
                os.path.join(WORKING_DIR, f"{environment}_mean_score.png"), dpi=200
            )
            plt.close(fig)


