def uniq(seq):
    out = []
    seen = set()
    for x in seq:
        if x not in seen:
            seen.add(x)
            out.append(x)
    return out


def is_num(x):
    return isinstance(x, (int, float, np.integer, np.floating)) and not isinstance(
        x, bool
    )


def sem(vals):
    vals = np.array([v for v in vals if is_num(v)], dtype=float)
    if len(vals) == 0:
        return np.nan
    if len(vals) == 1:
        return 0.0
    return float(np.std(vals, ddof=1) / np.sqrt(len(vals)))


def mean(vals):
    vals = [v for v in vals if is_num(v)]
    if not vals:
        return np.nan
    return float(np.mean(vals))


def group_metric(rows, metric):
    grouped = {}
    for r in rows:
        if not isinstance(r, dict):
            continue
        if (
            "environment" not in r
            or "planner" not in r
            or "per_decision_budget" not in r
            or metric not in r
        ):
            continue
        env = r["environment"]
        planner = r["planner"]
        budget = r["per_decision_budget"]
        val = r[metric]
        if not is_num(budget) or not is_num(val):
            continue
        grouped.setdefault((env, planner, budget), []).append(float(val))
    return grouped


